1	//! A lock-free skip list. See [`SkipList`].
2	
3	use alloc::alloc::handle_alloc_error;
4	use core::{
5	    alloc::Layout,
6	    cmp, fmt,
7	    marker::PhantomData,
8	    mem,
9	    ops::{Bound, Deref, RangeBounds},
10	    ptr,
11	    ptr::NonNull,
12	    sync::atomic::{AtomicUsize, Ordering, fence},
13	};
14	
15	use crossbeam_epoch::{self as epoch, Atomic, Collector, Guard, Shared};
16	use crossbeam_utils::CachePadded;
17	
18	use crate::{
19	    alloc_helper::Global,
20	    comparator::{BasicComparator, Comparator},
21	};
22	
23	/// Number of bits needed to store height.
24	const HEIGHT_BITS: usize = 5;
25	
26	/// Maximum height of a skip list tower.
27	const MAX_HEIGHT: usize = 1 << HEIGHT_BITS;
28	
29	/// The bits of `refs_and_height` that keep the height.
30	const HEIGHT_MASK: usize = (1 << HEIGHT_BITS) - 1;
31	
32	/// The tower of atomic pointers.
33	///
34	/// The actual size of the tower will vary depending on the height that a node
35	/// was allocated with.
36	#[repr(C)]
37	struct Tower<K, V> {
38	    pointers: [Atomic<Node<K, V>>; 0],
39	}
40	
41	/// A "reference" to a Tower that preserves provenance for accessing the dynamically sized tower.
42	///
43	/// A regular `&'a Tower<K, V>` would not have permission to access any bytes under stacked borrows
44	/// since Tower is a placeholder ZST.
45	///
46	/// Note, under tree borrows this isn't necessary.
47	struct TowerRef<'a, K, V> {
48	    ptr: NonNull<Tower<K, V>>,
49	    _marker: PhantomData<&'a Tower<K, V>>,
50	}
51	
52	impl<K, V> Clone for TowerRef<'_, K, V> {
53	    fn clone(&self) -> Self {
54	        *self
55	    }
56	}
57	impl<K, V> Copy for TowerRef<'_, K, V> {}
58	
59	impl<'a, K, V> TowerRef<'a, K, V> {
60	    /// Creates a TowerRef.
61	    ///
62	    /// # Safety
63	    ///
64	    /// Same as NonNull::as_ref, except the pointer must be valid for accessing the actual
65	    /// size of the tower.
66	    #[inline]
67	    unsafe fn new(ptr: NonNull<Tower<K, V>>) -> Self {
68	        Self {
69	            ptr,
70	            _marker: PhantomData,
71	        }
72	    }
73	
74	    /// Gets the atomic node pointer at the specified level of the tower.
75	    ///
76	    /// # Safety
77	    ///
78	    /// Index must be in bounds.
79	    #[inline]
80	    unsafe fn get_level(self, index: usize) -> &'a Atomic<Node<K, V>> {
81	        // SAFETY: Requirements passed to caller.
82	        unsafe { &*(self.ptr.as_ptr() as *const Atomic<Node<K, V>>).add(index) }
83	    }
84	}
85	
86	/// Tower at the head of a skip list.
87	///
88	/// This is located in the `SkipList` struct itself and holds a full height
89	/// tower.
90	#[repr(C)]
91	struct Head<K, V> {
92	    pointers: [Atomic<Node<K, V>>; MAX_HEIGHT],
93	}
94	
95	impl<K, V> Head<K, V> {
96	    /// Initializes a `Head`.
97	    #[inline]
98	    fn new() -> Self {
99	        // Initializing arrays in rust is a pain...
100	        Self {
101	            pointers: Default::default(),
102	        }
103	    }
104	
105	    /// Gets `TowerRef`
106	    #[inline]
107	    fn as_tower(&self) -> TowerRef<'_, K, V> {
108	        unsafe { TowerRef::new(NonNull::from(self).cast::<Tower<K, V>>()) }
109	    }
110	
111	    /// Gets the atomic node pointer at the specified level.
112	    ///
113	    /// # Safety
114	    ///
115	    /// Index must be in bounds.
116	    #[inline]
117	    unsafe fn get_level(&self, index: usize) -> &Atomic<Node<K, V>> {
118	        // SAFETY: Requirements passed to caller.
119	        unsafe { self.pointers.get_unchecked(index) }
120	    }
121	}
122	
123	/// A skip list node.
124	///
125	/// This struct is marked with `repr(C)` so that the specific order of fields is enforced.
126	/// It is important that the tower is the last field since it is dynamically sized. The key,
127	/// reference count, and height are kept close to the tower to improve cache locality during
128	/// skip list traversal.
129	#[repr(C)]
130	struct Node<K, V> {
131	    /// The value.
132	    value: V,
133	
134	    /// The key.
135	    key: K,
136	
137	    /// Keeps the reference count and the height of its tower.
138	    ///
139	    /// The reference count is equal to the number of `Entry`s pointing to this node, plus the
140	    /// number of levels in which this node is installed.
141	    refs_and_height: AtomicUsize,
142	
143	    /// The tower of atomic pointers.
144	    tower: Tower<K, V>,
145	}
146	
147	/// A "reference" to a Node that preserves provenance for accessing the dynamically sized tower at
148	/// the end of the node allocation.
149	///
150	/// Note, in a few situations below, we also rely on this for preserving write permissions.
151	struct NodeRef<'a, K, V> {
152	    ptr: NonNull<Node<K, V>>,
153	    _marker: PhantomData<&'a Node<K, V>>,
154	}
155	
156	impl<K, V> Clone for NodeRef<'_, K, V> {
157	    fn clone(&self) -> Self {
158	        *self
159	    }
160	}
161	impl<K, V> Copy for NodeRef<'_, K, V> {}
162	
163	impl<K, V> Node<K, V> {
164	    /// Allocates a node.
165	    ///
166	    /// The returned node will start with reference count of `ref_count` and the tower will be initialized
167	    /// with null pointers. However, the key and the value will be left uninitialized, and that is
168	    /// why this function is unsafe.
169	    unsafe fn alloc(height: usize, ref_count: usize) -> *mut Self {
170	        let layout = Self::get_layout(height);
171	        unsafe {
172	            let ptr = match Global.allocate(layout) {
173	                Some(ptr) => ptr.as_ptr().cast::<Self>(),
174	                None => handle_alloc_error(layout),
175	            };
176	
177	            ptr::addr_of_mut!((*ptr).refs_and_height)
178	                .write(AtomicUsize::new((height - 1) | (ref_count << HEIGHT_BITS)));
179	            ptr::addr_of_mut!((*ptr).tower.pointers)
180	                .cast::<Atomic<Self>>()
181	                .write_bytes(0, height);
182	            ptr
183	        }
184	    }
185	
186	    /// Deallocates a node.
187	    ///
188	    /// This function will not run any destructors.
189	    unsafe fn dealloc(ptr: *mut Self) {
190	        unsafe {
191	            let height = (*ptr).height();
192	            let layout = Self::get_layout(height);
193	            Global.deallocate(NonNull::new_unchecked(ptr.cast::<u8>()), layout);
194	        }
195	    }
196	
197	    /// Returns the layout of a node with the given `height`.
198	    fn get_layout(height: usize) -> Layout {
199	        assert!((1..=MAX_HEIGHT).contains(&height));
200	
201	        Layout::new::<Self>()
202	            .extend(Layout::array::<Atomic<Self>>(height).unwrap())
203	            .unwrap()
204	            .0
205	            .pad_to_align()
206	    }
207	
208	    /// Returns the height of this node's tower.
209	    #[inline]
210	    fn height(&self) -> usize {
211	        (self.refs_and_height.load(Ordering::Relaxed) & HEIGHT_MASK) + 1
212	    }
213	
214	    /// Attempts to increment the reference count of a node and returns `true` on success.
215	    ///
216	    /// The reference count can be incremented only if it is non-zero.
217	    ///
218	    /// # Panics
219	    ///
220	    /// Panics if the reference count overflows.
221	    #[inline]
222	    unsafe fn try_increment(&self) -> bool {
223	        let mut refs_and_height = self.refs_and_height.load(Ordering::Relaxed);
224	
225	        loop {
226	            // If the reference count is zero, then the node has already been
227	            // queued for deletion. Incrementing it again could lead to a
228	            // double-free.
229	            if refs_and_height & !HEIGHT_MASK == 0 {
230	                return false;
231	            }
232	
233	            // If all bits in the reference count are ones, we're about to overflow it.
234	            let new_refs_and_height = refs_and_height
235	                .checked_add(1 << HEIGHT_BITS)
236	                .expect("SkipList reference count overflow");
237	
238	            // Try incrementing the count.
239	            match self.refs_and_height.compare_exchange_weak(
240	                refs_and_height,
241	                new_refs_and_height,
242	                Ordering::Relaxed,
243	                Ordering::Relaxed,
244	            ) {
245	                Ok(_) => return true,
246	                Err(current) => refs_and_height = current,
247	            }
248	        }
249	    }
250	
251	    /// Drops the key and value of a node, then deallocates it.
252	    #[cold]
253	    unsafe fn finalize(ptr: *mut Self) {
254	        unsafe {
255	            // Call destructors: drop the key and the value.
256	            ptr::drop_in_place(&mut (*ptr).key);
257	            ptr::drop_in_place(&mut (*ptr).value);
258	
259	            // Finally, deallocate the memory occupied by the node.
260	            Self::dealloc(ptr);
261	        }
262	    }
263	}
264	
265	impl<'a, K, V> NodeRef<'a, K, V> {
266	    /// Creates a NodeRef.
267	    ///
268	    /// # Safety
269	    ///
270	    /// Same as NonNull::as_ref, except the pointer must also be valid for accessing the actual
271	    /// size of the tower at the end of the node.
272	    #[inline]
273	    unsafe fn new(ptr: NonNull<Node<K, V>>) -> Self {
274	        Self {
275	            ptr,
276	            _marker: PhantomData,
277	        }
278	    }
279	
280	    /// # Safety
281	    ///
282	    /// See [`Shared::as_ref`].
283	    #[inline]
284	    unsafe fn from_shared(shared: Shared<'a, Node<K, V>>) -> Option<Self> {
285	        if let Some(ptr) = NonNull::new(shared.as_raw() as *mut Node<K, V>) {
286	            Some(unsafe { Self::new(ptr) })
287	        } else {
288	            None
289	        }
290	    }
291	
292	    /// Decrements the reference count of a node, destroying it if the count becomes zero.
293	    #[inline]
294	    unsafe fn decrement(self, guard: &Guard) {
295	        if self
296	            .refs_and_height
297	            .fetch_sub(1 << HEIGHT_BITS, Ordering::Release)
298	            >> HEIGHT_BITS
299	            == 1
300	        {
301	            fence(Ordering::Acquire);
302	            unsafe { guard.defer_unchecked(move || Node::finalize(self.ptr.as_ptr())) }
303	        }
304	    }
305	
306	    /// Decrements the reference count of a node, pinning the thread and destroying the node
307	    /// if the count become zero.
308	    #[inline]
309	    unsafe fn decrement_with_pin<F, C>(self, parent: &SkipList<K, V, C>, pin: F)
310	    where
311	        F: FnOnce() -> Guard,
312	    {
313	        if self
314	            .refs_and_height
315	            .fetch_sub(1 << HEIGHT_BITS, Ordering::Release)
316	            >> HEIGHT_BITS
317	            == 1
318	        {
319	            fence(Ordering::Acquire);
320	            let guard = &pin();
321	            parent.check_guard(guard);
322	            unsafe { guard.defer_unchecked(move || Node::finalize(self.ptr.as_ptr())) }
323	        }
324	    }
325	
326	    /// Marks all pointers in the tower and returns `true` if the level 0 was not marked.
327	    fn mark_tower(self) -> bool {
328	        let height = self.height();
329	
330	        for level in (0..height).rev() {
331	            let tag = unsafe {
332	                // We're loading the pointer only for the tag, so it's okay to use
333	                // `epoch::unprotected()` in this situation.
334	                // TODO(Amanieu): can we use release ordering here?
335	                self.get_level(level)
336	                    .fetch_or(1, Ordering::SeqCst, epoch::unprotected())
337	                    .tag()
